function.body:
pInstance RECORD;
	vMessageOK VARCHAR2(2000) := '';
	vMessageError VARCHAR2(2000) := '';
	vRecordID VARCHAR2(32);
	vUserID VARCHAR2(32);
	vRecord RECORD;
	vTmp RECORD;
	vMovementID VARCHAR2(32);
	vProduct RECORD;
	vLocatorID VARCHAR2(32);
	vCheck NUMBER(2,0) := 0;
	vLine NUMBER;
	vAttributeSetInstanceID VARCHAR2(32);
	vDocumentno VARCHAR2(32);
	vRoundAmount NUMBER;
BEGIN
	DBMS_OUTPUT.PUT_LINE( 'Updating PInstance - Processing ' || pInstanceID);
	vMessageError := 'PInstanceNotFound';
 AD_UPDATE_PINSTANCE(pInstanceID, NULL, 'Y', NULL, NULL);
	BEGIN
		--Obtener los parametros
		FOR pInstance IN (
			SELECT
				i.Record_ID,
				i.AD_User_ID,
				p.ParameterName,
				p.P_String,
				p.P_Number,
				p.P_Date
			FROM AD_PInstance AS i
				LEFT JOIN AD_PInstance_Para AS p ON i.AD_PInstance_ID=p.AD_PInstance_ID
			WHERE i.AD_PInstance_ID=pInstanceID
			ORDER BY p.SeqNo
		) LOOP
			vRecordID := pInstance.Record_ID;
			vUserID := pInstance.AD_User_ID;
		END LOOP;

		SELECT * INTO vRecord FROM MA_WorkRequirement WHERE MA_WorkRequirement_ID=vRecordID;

		SELECT ad_sequence_doc('DocumentNo_M_Movement','C8B2F3C65E7547E5835C910E4039C86F','Y') INTO vDocumentno;

		INSERT INTO	M_Movement (
			m_movement_id,
			ad_client_id,
			ad_org_id,
			createdby,
			updatedby,
			name,
			description,
			movementdate,
			documentno,
			EM_Ssfin_Ma_Workreq_ID
		) VALUES (
			get_uuid(),
			vRecord.ad_client_id,
			vRecord.ad_org_id,
			vUserID,
			vUserID,
			TO_CHAR(now(), 'DD-MM-YYYY HH24:MI:SS')||' - ORDEN DE FABRICACIÓN #'||vRecord.documentno,
			vRecord.documentno,
			now(),
			vDocumentno,
			vRecord.MA_WorkRequirement_ID
		) RETURNING m_movement_id INTO vMovementID;

		FOR vTmp IN (
			SELECT * FROM MA_WRPhase
			WHERE MA_WorkRequirement_ID=vRecordID
			ORDER BY SeqNo
		) LOOP
			FOR vProduct IN (
				SELECT fp.*, pr.name, pr.value
				FROM MA_WRPhaseProduct AS fp
					JOIN M_Product AS pr ON pr.M_Product_ID=fp.M_Product_ID
				WHERE fp.MA_WRPhase_ID=vTmp.MA_WRPhase_ID AND fp.productiontype='-'
			) LOOP
				SELECT M_Locator_ID INTO vLocatorID
				FROM M_Product_Org
				WHERE M_Product_ID=vProduct.M_Product_ID
				ORDER BY created DESC
				LIMIT 1;

				select CostingPrecision into vRoundAmount 
				from ad_org ao
				join c_currency cu on cu.c_currency_id=ao.c_currency_id
				where ao.IsSummary='Y';

				IF vLocatorID IS NULL THEN
					RAISE_APPLICATION_ERROR(-20000, 'No se encontro hueco de origen del producto '||vProduct.name);
				END IF;

				SELECT M_AttributeSetInstance_ID INTO vAttributeSetInstanceID
				FROM M_Storage_Detail
				WHERE M_Product_ID=vProduct.M_Product_ID AND QtyOnHand>=vProduct.MovementQty
				LIMIT 1;

				SELECT COALESCE(MAX(line),0)+10 INTO vLine FROM M_MovementLine WHERE m_movement_id=vMovementID;

				INSERT INTO M_MovementLine (
					m_movementline_id,
					ad_client_id,
					ad_org_id,
					createdby,
					updatedby,
					m_movement_id,
					m_locator_id,
					m_locatorto_id,
					m_product_id,
					line,
					movementqty,
					m_attributesetinstance_id,
					c_uom_id,
					c_aum,
					aumqty,
					em_sprli_identifier
				) VALUES (
					get_uuid(),
					vRecord.ad_client_id,
					vRecord.ad_org_id,
					vUserID,
					vUserID,
					vMovementID,
					vLocatorID,
					vProduct.EM_Spatmp_Inventory_Location,
					vProduct.M_Product_ID,
					vLine,
					round((vTmp.Quantity*vProduct.MovementQty),6),
					vAttributeSetInstanceID,
					vProduct.c_uom_id,
					vProduct.c_uom_id,
					0,
					vProduct.value
				);

				vCheck := 1;

			END LOOP;
		END LOOP;

		IF vCheck=0 THEN
			RAISE_APPLICATION_ERROR(-20000, 'No existen productos para generar el movimiento');
		END IF;

		UPDATE MA_WorkRequirement SET em_ssprodp_movement_id=vMovementID WHERE MA_WorkRequirement_ID=vRecordID;

		vMessageOK := 'SE HA GENERADO UNA ENTREGA DE MATERIAS NECESARIAS PARA LA PRODUCCIÓN CON EL NUMERO: '||vDocumentno;
		DBMS_OUTPUT.PUT_LINE( 'Updating PInstance - Finished ' || vMessageOK);
	 AD_UPDATE_PINSTANCE(pInstanceID, NULL, 'N', 1, vMessageOK);
	END;

	EXCEPTION WHEN OTHERS THEN
	vMessageError := '@ERROR=' || SQLERRM;
	DBMS_OUTPUT.PUT_LINE( vMessageError);
 AD_UPDATE_PINSTANCE(pInstanceID, NULL, 'N', 0, vMessageError);
END SSPRODP_GENERATE_MOVEMENT
